import React, { useState } from 'react';

const RatingComponent = ({ phraseId, userRating, onRatingSubmit }) => {
  const [rating, setRating] = useState(userRating || 0);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    const value = parseInt(e.target.value, 10);
    if (value >= 0 && value <= 5) {
      setRating(value);
      setError(null);
    } else {
      setError('Rating must be an integer between 0 and 5.');
    }
  };

  const handleSubmit = () => {
    if (rating >= 0 && rating <= 5) {
      onRatingSubmit(phraseId, rating);
      setError(null);
    } else {
      setError('Please enter a valid rating before submitting.');
    }
  };

  return (
    <div>
      <label htmlFor={`rating-${phraseId}`}>Rate this phrase: </label>
      <input
        id={`rating-${phraseId}`}
        type="number"
        min="0"
        max="5"
        value={rating}
        onChange={handleChange}
        aria-label="Rating from 0 to 5"
      />
      <button onClick={handleSubmit}>Submit</button>
      {error && <div style={{ color: 'red' }}>{error}</div>}
    </div>
  );
};

export default RatingComponent;

