const express = require('express');
const router = express.Router();
const { body, validationResult } = require('express-validator');
const authenticate = require('../middleware/authenticate');
const Rating = require('../models/Rating');

// POST /api/ratings
router.post(
  '/',
  authenticate,
  body('phraseId').isInt().withMessage('Phrase ID must be an integer.'),
  body('rating')
    .isInt({ min: 0, max: 5 })
    .withMessage('Rating must be an integer between 0 and 5.'),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { phraseId, rating } = req.body;
    const userId = req.user.id;

    try {
      // Upsert rating: update if exists, else create
      let userRating = await Rating.findOne({ phraseId, userId });
      if (userRating) {
        userRating.rating = rating;
        await userRating.save();
      } else {
        userRating = new Rating({ phraseId, userId, rating });
        await userRating.save();
      }
      res.status(200).json({ message: 'Rating saved successfully.' });
    } catch (err) {
      console.error(err);
      res.status(500).json({ error: 'Server error saving rating.' });
    }
  }
);

module.exports = router;

