import React, { useEffect, useState } from 'react';
import RatingComponent from './RatingComponent';
import { submitRating } from '../api/ratingsApi';

const PhraseDisplay = ({ phrase, user, token }) => {
  const [averageRating, setAverageRating] = useState(null);
  const [userRating, setUserRating] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    // Fetch average rating and user rating for the phrase
    const fetchRatings = async () => {
      try {
        const res = await fetch(`/api/phrases/${phrase.id}/ratings`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error('Failed to fetch ratings');
        const data = await res.json();
        setAverageRating(data.averageRating);
        setUserRating(data.userRating);
      } catch (err) {
        setError('Could not load ratings');
      }
    };
    if (token) fetchRatings();
  }, [phrase.id, token]);

  const handleRatingSubmit = async (phraseId, rating) => {
    try {
      await submitRating(phraseId, rating, token);
      setUserRating(rating);
      // Optionally refresh average rating
      // ...
      setError(null);
    } catch (err) {
      setError(err.error || 'Error submitting rating');
    }
  };

  return (
    <div>
      <p>{phrase.text}</p>
      {averageRating !== null && <p>Average Rating: {averageRating.toFixed(2)}</p>}
      {token ? (
        <RatingComponent
          phraseId={phrase.id}
          userRating={userRating}
          onRatingSubmit={handleRatingSubmit}
        />
      ) : (
        <p>Please log in to rate this phrase.</p>
      )}
      {error && <div style={{ color: 'red' }}>{error}</div>}
    </div>
  );
};

export default PhraseDisplay;
